INSERT INTO `aboutsetting` (`id`, `heroTitle`, `heroSubtitle`, `heroImageUrl`, `historyTitle`, `historyText`, `historyImageUrl`, `visionTitle`, `visionText`, `missionTitle`, `missionItems`, `leaders`, `footerDescription`, `address`, `email`, `phone`, `mapEmbedUrl`, `imamDuty`, `muadzinDuty`, `social`, `updatedBy`, `createdAt`) VALUES
(1, 'Tentang Masjid Kagawa', 'Sejarah • Visi Misi • Struktur Pengurus', '', 'Sejarah Masjid', '<p>Masjid Kagawa merupakan bagian dari perjalanan panjang komunitas Muslim di Prefektur Kagawa dalam membangun pusat ibadah dan pembinaan yang terorganisir, berkelanjutan, dan diakui secara hukum di Jepang.</p><p>Cikal bakal pendiriannya berawal dari kebutuhan komunitas Muslim—baik warga lokal maupun internasional—akan sebuah tempat yang tidak hanya berfungsi sebagai ruang ibadah, tetapi juga sebagai pusat dakwah, pendidikan, dan kegiatan sosial.</p><p>Untuk mewujudkan hal tersebut secara sistematis dan legal, pada tanggal <strong>3 Juli 2020 (令和2年7月3日)</strong> didirikan sebuah badan hukum resmi berbentuk: <strong>KMIK一般社団法人 (KMIK General Incorporated Association) </strong>yang berlokasi di: <strong>香川県坂出市江尻町1547番地1</strong></p><p>Organisasi ini dibentuk dengan tujuan utama untuk:</p><ul><li>Mengembangkan dakwah Islam di Jepang</li><li>Membina keimanan dan keislaman Muslim</li><li>Menyelenggarakan pendidikan Islam</li><li>Mengelola kegiatan sosial, budaya, dan kemasyarakatan</li><li>Mengoperasikan fasilitas ibadah seperti masjid</li></ul><p>Seiring berjalannya waktu, upaya tersebut berkembang hingga akhirnya diwujudkan dalam bentuk fisik Masjid Kagawa sebagai pusat aktivitas umat Islam.</p><p>Masjid Kagawa secara resmi diresmikan pada:</p><p>👉 <strong>30 November 2025</strong></p><p>Sejak peresmiannya, Masjid Kagawa telah menjadi:</p><ul><li>Pusat ibadah harian dan shalat Jumat</li><li>Tempat kajian dan halaqah keilmuan</li><li>Ruang pembinaan generasi Muslim</li><li>Titik temu komunitas Muslim multinasional di Shikoku</li><li>Jembatan interaksi antara masyarakat Jepang dan komunitas Muslim</li></ul><p>Dengan landasan hukum yang kuat dan visi dakwah yang jelas, Masjid Kagawa terus berkembang sebagai institusi yang tidak hanya melayani kebutuhan spiritual, tetapi juga berperan aktif dalam membangun harmoni sosial dan pemahaman lintas budaya di Jepang.</p>', '', 'Visi', 'Menjadi pusat peradaban Islam yang unggul di Jepang, yang mengintegrasikan ibadah, ilmu, dan kontribusi sosial dalam membangun masyarakat yang beriman, berilmu, dan berakhlak mulia.', 'Misi', '[\"Menyelenggarakan ibadah yang sesuai dengan Al-Qur’an dan Sunnah secara konsisten dan berkualitas\",\"Mengembangkan program pendidikan Islam untuk semua kalangan, dari anak-anak hingga dewasa\",\"Membina komunitas Muslim yang solid, inklusif, dan saling mendukung\",\"Menjadi pusat dakwah yang menyampaikan Islam dengan hikmah dan profesionalisme\",\"Mengembangkan kegiatan sosial dan kemanusiaan bagi masyarakat luas\",\"Memperkenalkan nilai-nilai Islam kepada masyarakat Jepang secara bijaksana dan kontekstual\",\"Membangun hubungan harmonis antara komunitas Muslim dan masyarakat lokal\",\"Mengelola masjid secara profesional, transparan, dan berkelanjutan\"]', '[{\"role\":\"Ketua\",\"name\":\"Zulfikar\",\"imageUrl\":\"/uploads/about/1779197413072-756554340.jpg\",\"note\":\"\"},{\"role\":\"Pengurus Harian\",\"name\":\"Regi Wijaya Sasmita\",\"imageUrl\":\"/uploads/about/1779197487505-392491112.jpg\",\"note\":\"\"},{\"role\":\"Pengurus Praktik Purna Tugas\",\"name\":\"Dihyah bin Nasarudin\",\"imageUrl\":\"/uploads/about/1779197650354-527771132.jpg\",\"note\":\"10 Januari 2026 - 10 April 2026\"},{\"role\":\"Pengurus Praktik Purna Tugas\",\"name\":\"Harith Naufal bin Mohd. Hilmi\",\"imageUrl\":\"/uploads/about/1779197755006-895181182.jpg\",\"note\":\"10 Januari 2026 - 10 April 2026\"},{\"role\":\"Pengurus Praktik Aktif\",\"name\":\"Ahmad Ali Akbar bin Mohmmad\",\"imageUrl\":\"/uploads/about/1779197866651-286900660.jpg\",\"note\":\"10 April 2026 - 10 April 2026\"},{\"role\":\"Pengurus Praktik Aktif\",\"name\":\"Hilmi Haikal bin Mohd. Riduan\",\"imageUrl\":\"/uploads/about/1779225950157-363041990.jpg\",\"note\":\"\"}]', '', '1547-1 Ejiricho, Sakaide, Kagawa 762-0011', 'admin@masjidkagawa.com', '+81 80-3925-7598', '<div class=\"mapouter\"><div class=\"gmap_canvas\"><iframe class=\"gmap_iframe\" frameborder=\"0\" scrolling=\"no\" marginheight=\"0\" marginwidth=\"0\" src=\"https://maps.google.com/maps?width=600&amp;height=400&amp;hl=en&amp;q=1547-1 Ejiricho, Sakaide, Kagawa 762-0011&amp;t=&amp;z=14&amp;ie=UTF8&amp;iwloc=B&amp;output=embed\"></iframe><a href=\"https://embed-googlemap.com\">google map embed html</a></div><style>.mapouter{position:relative;text-align:right;width:600px;height:400px;}.gmap_canvas {overflow:hidden;background:none!important;width:600px;height:400px;}.gmap_iframe {width:600px!important;height:400px!important;}</style></div>', 'Regi Wijaya Sasmita', '', '{\"facebook\":\"https://www.facebook.com/share/18THaS9uLY/?mibextid=wwXIfr\",\"instagram\":\"https://www.instagram.com/masjidkagawa?igsh=MXduM2N5dGoxZjJxcQ%3D%3D&utm_source=qr\",\"youtube\":\"https://www.youtube.com/@masjid.kagawa\"}', 1, '2026-05-19 06:19:16.536');

