INSERT INTO `activity` (`id`, `title`, `category`, `date`, `startTime`, `endTime`, `location`, `description`, `imageUrl`, `isPublished`, `createdBy`, `updatedBy`, `createdAt`, `isFeatured`, `type`, `ustadz`) VALUES
(1, 'Penyambutan Imam Masjid Kagawa', 'Event Besar', '2026-01-31 00:00:00.000', '20:00', '21:00', 'Masjid Kagawa', '<p>Masjid Kagawa dengan penuh rasa syukur mengundang seluruh kaum Muslimin di Kagawa dan sekitarnya untuk menghadiri acara <strong>Penyambutan Imam Masjid Kagawa</strong>, sebuah momen istimewa dalam menyambut generasi penghafal Al-Qur’an yang akan berkontribusi dalam pembinaan umat.</p><p>Kegiatan ini menjadi langkah penting dalam memperkuat peran masjid sebagai pusat ibadah, pendidikan, dan pembinaan generasi Qur’ani. Kehadiran para imam muda yang menghafal Al-Qur’an diharapkan dapat menjadi inspirasi sekaligus pendorong semangat bagi seluruh jamaah untuk semakin dekat dengan Al-Qur’an, baik dalam membaca, memahami, mengamalkan, maupun mengajarkannya.</p><p>Acara ini juga akan diisi dengan <strong>tausiah islami oleh Ustaz Adnan</strong> dengan tema:</p><blockquote><em>“Membaca, Memahami, Mengamalkan, dan Mengajarkan Al-Qur’an”</em></blockquote><p>Tema ini mengingatkan kita bahwa hubungan dengan Al-Qur’an bukan hanya sebatas tilawah, tetapi juga mencakup pemahaman mendalam, pengamalan dalam kehidupan sehari-hari, serta penyebaran ilmu kepada orang lain.</p><p>Selain itu, kegiatan ini akan menjadi ajang <strong>silaturahmi dan kebersamaan antar jamaah</strong>, yang akan ditutup dengan ramah tamah dan makan bersama dalam suasana kekeluargaan.</p><p>Mari hadir dan menjadi bagian dari momen penuh berkah ini, serta dukung lahirnya generasi Qur’ani penerus umat.</p><p><br></p><h2>📌 Detail Kegiatan</h2><ul><li><strong>Waktu</strong>: Setelah Shalat Isya (sekitar pukul 20.00)</li><li><strong>Tempat</strong>: Masjid Kagawa</li><li><strong>Pemateri</strong>: Ustaz Adnan</li></ul><h3>Rangkaian Acara:</h3><ol><li>Penyambutan Imam</li><li>Tausiah Islami</li><li>Ramah Tamah &amp; Makan Bersama</li></ol><p>Semoga Allah memberkahi langkah kita dan menjadikan kita termasuk orang-orang yang mencintai dan dekat dengan Al-Qur’an.</p>', '/uploads/activities/1779947564121-448894103.jpg', 1, 1, 1, '2026-05-28 05:53:46.174', 1, 'kegiatan', ''),
(2, 'Landasan Pokok Beragama: Pertemuan 1 - Mukadimah', 'Aqidah', '2026-01-24 00:00:00.000', '19:00', '21:00', 'Masjid Kagawa', '<h2>🕌 Pengajian Sabtu Malam Masjid Kagawa</h2><p>Masjid Kagawa mengundang seluruh kaum Muslimin yang berada di Kagawa dan sekitarnya untuk menghadiri kegiatan <strong>Pengajian Sabtu Malam</strong>, sebuah majelis ilmu yang diharapkan menjadi sarana memperkuat iman, menambah wawasan keislaman, serta mempererat ukhuwah Islamiyah di tengah kehidupan masyarakat Jepang.</p><p>Kegiatan ini akan diisi dengan rangkaian acara yang penuh manfaat, mulai dari <strong>silaturahmi dan ramah tamah</strong>, dilanjutkan dengan <strong>shalat Isya berjamaah</strong>, serta <strong>kajian ilmiah</strong> yang membahas <em>landasan pokok beragama</em> sebagai bekal dalam menjalani kehidupan sebagai Muslim.</p><p>Kajian ini juga menjadi bagian dari upaya membangun komunitas Muslim yang kuat, saling mendukung, dan terus berkembang dalam kebaikan, khususnya bagi saudara-saudara kita yang tinggal jauh dari negeri Muslim.</p><p>Sebagaimana sabda Rasulullah ﷺ:</p><p><em>\"Siapa yang menempuh jalan untuk mencari ilmu, maka Allah akan mudahkan baginya jalan menuju surga.\"</em></p><p> (HR. Muslim no. 2699)</p><p>InsyaaAllah, kegiatan ini juga akan ditutup dengan <strong>makan malam bersama</strong>, sebagai bentuk kebersamaan dan mempererat hubungan antar sesama jamaah.</p><p>Mari hadir dan ambil bagian dalam majelis ilmu ini.</p><p> Semoga Allah memberkahi langkah kita dan menjadikan kita termasuk hamba-hamba-Nya yang mencintai ilmu.</p><h2>📌 Detail Kegiatan</h2><ul><li><strong>Hari/Tanggal</strong>: Sabtu, 23 Januari 2026</li><li><strong>Waktu</strong>:</li><li class=\"ql-indent-1\">19.00 – Silaturahmi &amp; Ramah Tamah</li><li class=\"ql-indent-1\">20.00 – Shalat Isya &amp; Kajian</li><li><strong>Tempat</strong>: Masjid Kagawa</li><li><strong>Pemateri</strong>: Ustadz Regi Wijaya Sasmita</li><li><strong>Tema Kajian</strong>: Landasan Pokok Beragama (Pertemuan 1 – Mukadimah)&nbsp;</li></ul><p><br></p>', '/uploads/activities/1779958718923-902246886.jpg', 1, 1, 1, '2026-05-28 09:02:12.029', 1, 'kajian', 'Regi Wijaya Sasmia'),
(3, 'Prinsip Dasar Islam', 'Aqidah', '2026-01-31 00:00:00.000', '19:00', '21:00', 'Masjid Kagawa', '<p>Masjid Kagawa mengundang seluruh kaum Muslimin di Kagawa dan sekitarnya untuk menghadiri kegiatan <strong>Pengajian Sabtu Malam</strong>, sebuah majelis ilmu yang bertujuan untuk memperkuat keimanan dan pemahaman dasar dalam Islam.</p><p>Kajian ini akan disampaikan oleh <strong>Dihyah bin Nasarudin</strong> dengan tema <strong>“Prinsip Dasar Islam”</strong>, yang membahas fondasi penting dalam memahami agama secara benar, mulai dari keyakinan hingga pengamalan dalam kehidupan sehari-hari.</p><p>Acara akan dimulai dengan <strong>ramah tamah pada pukul 19.00</strong>, dilanjutkan dengan <strong>kajian setelah shalat Isya pukul 20.00</strong>. Kegiatan ini juga menjadi sarana untuk mempererat ukhuwah Islamiyah antar jamaah di lingkungan Masjid Kagawa.</p><p>Selain itu, peserta juga akan mendapatkan kesempatan untuk menikmati <strong>makan malam bersama</strong>, sehingga suasana kebersamaan semakin terasa hangat dan penuh keberkahan.</p><p>📍 <strong>Tempat:</strong> Masjid Kagawa</p><p> 📅 <strong>Waktu:</strong> Sabtu, 31 Januari 2026</p><p>Mari hadir dan manfaatkan kesempatan ini untuk menuntut ilmu, karena Rasulullah ﷺ bersabda:</p><p><em>\"Barangsiapa yang menempuh jalan untuk mencari ilmu, maka Allah akan mudahkan baginya jalan menuju surga.\"</em></p><p> (HR. Muslim)</p>', '/uploads/activities/1779959717917-414997005.jpg', 1, 1, 1, '2026-05-28 09:16:27.172', 0, 'kajian', 'Dihyah bin Nasarudin'),
(4, 'Fiqih: Bab Thaharah', 'Fiqih', '2026-02-07 00:00:00.000', '19:00', '21:00', 'Masjid Kagawa', '<p>Masjid Kagawa kembali mengundang seluruh kaum Muslimin di Kagawa dan sekitarnya untuk menghadiri <strong>Pengajian Sabtu Malam</strong>, sebuah majelis ilmu yang rutin diselenggarakan sebagai sarana memperdalam pemahaman agama dan memperkuat keimanan.</p><p>Pada kesempatan kali ini, kajian akan membahas tema <strong>“Fiqih: Bab Thaharah”</strong>, yang merupakan salah satu pembahasan dasar dalam Islam terkait <strong>bersuci</strong>, baik dari hadats maupun najis, sebagai syarat sah dalam beribadah.</p><p>Kajian ini akan disampaikan oleh <strong>Harith Naufal bin Muhammad Hilmi</strong>, dengan penyampaian yang insyaaAllah mudah dipahami dan aplikatif dalam kehidupan sehari-hari.</p><p>Acara akan dimulai dengan <strong>ramah tamah pada pukul 19.00</strong>, kemudian dilanjutkan dengan <strong>kajian setelah shalat Isya pada pukul 20.00</strong>. Kegiatan ini juga menjadi momen untuk mempererat ukhuwah dan membangun kebersamaan antar jamaah.</p><p>📅 <strong>Hari &amp; Tanggal:</strong> Sabtu, 7 Februari 2026</p><p> 📍 <strong>Tempat:</strong> Masjid Kagawa</p><p>Mari hadir dan manfaatkan kesempatan ini untuk menuntut ilmu yang bermanfaat, karena setiap langkah menuju majelis ilmu adalah jalan menuju kebaikan dan keberkahan.</p><p><em>\"Barangsiapa yang menempuh jalan untuk mencari ilmu, maka Allah akan mudahkan baginya jalan menuju surga.\"</em></p><p> (HR. Muslim)</p>', '/uploads/activities/1779960394831-450957179.jpg', 1, 1, 1, '2026-05-28 09:27:48.144', 0, 'kajian', 'Harith Naufal bin Mohd. Hilmi');

