INSERT INTO `post` (`id`, `title`, `slug`, `excerpt`, `content`, `imageUrl`, `category`, `author`, `isPublished`, `isFeatured`, `createdBy`, `updatedBy`, `createdAt`, `updatedAt`) VALUES
(1, 'Peresmian Masjid Kagawa: Tonggak Baru Dakwah Islam di Jepang', 'peresmian-masjid-kagawa-tonggak-baru-dakwah-islam-di-jepang', 'Masjid Kagawa resmi dibuka dalam sebuah acara peresmian yang khidmat dan penuh kebersamaan. Kegiatan ini dihadiri oleh berbagai kalangan masyarakat sebagai simbol hadirnya pusat ibadah dan dakwah Islam di wilayah Kagawa.', '<p>&lt;p&gt;Masjid Kagawa resmi dibuka dalam sebuah acara peresmian yang berlangsung pada tanggal &lt;strong&gt;30 November 2025&lt;/strong&gt;. Kegiatan ini dilaksanakan dengan penuh kekhidmatan dan suasana kebersamaan, menjadi momen bersejarah bagi umat Islam di wilayah Kagawa dan sekitarnya.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Peresmian ini bukan sekadar pembukaan sebuah bangunan fisik, namun juga menjadi &lt;strong&gt;tonggak baru dalam penguatan dakwah Islam di Jepang&lt;/strong&gt;, khususnya di Prefektur Kagawa. Kehadiran masjid ini diharapkan mampu menjadi pusat aktivitas keislaman yang membawa manfaat luas bagi umat, baik dari sisi ibadah, pendidikan, maupun sosial.&lt;/p&gt;</p><p><br></p><p>&lt;h2&gt;Pembukaan yang Penuh Keberkahan&lt;/h2&gt;</p><p><img src=\"data:image/jpeg;base64,\"></p><p>&lt;p&gt;Acara dimulai dengan pembukaan dan pembacaan ayat suci Al-Qur’an yang menambah keberkahan suasana. Lantunan ayat-ayat suci tersebut menghadirkan ketenangan sekaligus menguatkan nilai spiritual dalam momen yang sangat bersejarah ini.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Selanjutnya, para tamu undangan mendapatkan sambutan serta penjelasan mengenai latar belakang dan tujuan didirikannya Masjid Kagawa. Dalam penyampaiannya, dijelaskan bahwa masjid ini diharapkan menjadi &lt;strong&gt;pusat ibadah, pembinaan umat, serta penguatan nilai-nilai Islam di tengah masyarakat Jepang&lt;/strong&gt;.&lt;/p&gt;</p><p><br></p><p>&lt;h2&gt;Kehadiran Berbagai Kalangan Masyarakat&lt;/h2&gt;</p><p>&lt;p&gt;Acara peresmian ini turut dihadiri oleh berbagai kalangan masyarakat, baik dari komunitas Muslim maupun non-Muslim. Hal ini menunjukkan tingginya antusiasme serta semangat kebersamaan lintas budaya yang terbangun di wilayah Kagawa.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Kehadiran para tamu dari berbagai latar belakang menjadi simbol bahwa masjid tidak hanya berfungsi sebagai tempat ibadah, tetapi juga sebagai &lt;strong&gt;ruang interaksi sosial dan jembatan yang menghubungkan berbagai komunitas&lt;/strong&gt;.&lt;/p&gt;</p><p><br></p><p>&lt;h2&gt;Prosesi Peresmian dan Momen Haru&lt;/h2&gt;</p><p><img src=\"/uploads/posts/1779945718840-733884027.jpeg\"></p><p>&lt;p&gt;Salah satu rangkaian utama dalam kegiatan ini adalah prosesi pemotongan pita sebagai tanda resmi dibukanya Masjid Kagawa. Momen tersebut berlangsung dengan penuh haru dan rasa syukur, disambut hangat oleh seluruh hadirin yang hadir.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Suasana kebahagiaan dan rasa syukur begitu terasa, mengingat perjuangan panjang yang telah dilalui hingga akhirnya masjid ini dapat berdiri dan diresmikan secara resmi.&lt;/p&gt;</p><p><br></p><p>&lt;h2&gt;Ceramah Inspiratif oleh Sugimoto Kyouichiro Sensei&lt;/h2&gt;</p><p><img src=\"/uploads/posts/1779945744942-982664554.jpeg\"></p><p>&lt;p&gt;Dalam kesempatan ini, acara juga diisi dengan ceramah yang disampaikan oleh &lt;strong&gt;Sugimoto Kyouichiro Sensei&lt;/strong&gt;. Dalam ceramahnya, beliau menyampaikan pentingnya hidup berdampingan dalam keberagaman serta bagaimana umat Islam dapat memberikan kontribusi positif dalam masyarakat global.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Penyampaian beliau memberikan wawasan yang mendalam sekaligus menguatkan nilai-nilai &lt;strong&gt;toleransi, saling memahami, dan membangun hubungan harmonis antar masyarakat&lt;/strong&gt;, khususnya di lingkungan yang multikultural seperti Jepang.&lt;/p&gt;</p><p><br></p><p>&lt;h2&gt;Ramah Tamah dan Kebersamaan&lt;/h2&gt;</p><p><br></p><p>&lt;p&gt;Setelah rangkaian acara utama selesai, kegiatan dilanjutkan dengan sesi tanya jawab serta ramah tamah. Para peserta tampak menikmati suasana kebersamaan, saling berinteraksi, dan menjalin hubungan yang lebih dekat satu sama lain.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Acara kemudian ditutup dengan hidangan halal yang telah disediakan, menambah kehangatan suasana dan mempererat ukhuwah di antara para hadirin.&lt;/p&gt;</p><p><br></p><p>&lt;h2&gt;Harapan ke Depan&lt;/h2&gt;</p><p><br></p><p>&lt;p&gt;Dengan diresmikannya Masjid Kagawa, diharapkan masjid ini dapat menjadi &lt;strong&gt;pusat kegiatan keislaman yang aktif&lt;/strong&gt;, tempat belajar bagi generasi muda, serta wadah bagi umat Islam untuk memperkuat ukhuwah dan kontribusi positif di tengah masyarakat Jepang.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;Masjid ini juga diharapkan menjadi simbol keberadaan Islam yang membawa rahmat, kedamaian, dan manfaat bagi seluruh masyarakat tanpa memandang latar belakang.&lt;/p&gt;</p><p><br></p><p>&lt;p&gt;&lt;strong&gt;Semoga Masjid Kagawa senantiasa diberkahi dan menjadi sumber kebaikan yang terus mengalir bagi umat.&lt;/strong&gt;&lt;/p&gt;</p>', '/uploads/posts/1779263288926-855887390.jpg', 'Artikel', 'Admin Masjid Kagawa', 1, 1, NULL, NULL, '2026-05-20 07:54:43.434', '2026-05-28 09:35:19.329');

